class Solution {
    public int minimumChanges(String s, int k) {
        int n = s.length();
        int ans = Integer.MAX_VALUE;
        for (int d = 1; d <= n / 2; d++) {
            if (n % d == 0) {
                int cnt = 0;
                for (int i = 0; i < d; i++) {
                    int j = i;
                    while (j < n) {
                        if (s.charAt(j) != s.charAt(j + d)) cnt++;
                        j += d + 1;
                    }
                }
                ans = Math.min(ans, cnt);
            }
        }
        return ans;
    }
}
